def binSearch(arr: list[int], target: int) -> int:
    if len(arr) == 0:
        return -1

    l, r = 0, len(arr) - 1

    while l <= r:
        mid = (l + r) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] > target:
            r = mid - 1
        else:
            l = mid + 1

    return -1

