function LCS_length_DP(X[1...m], Y[1...n]) -> number:
	dpTable = Array(shape=(m + 1, n + 1))

	for j = 1 to n + 1:
		dpTable[m + 1, j] = 0
	for i = 1 to m:
		dpTable[i, n + 1] = 0

	lcsChoices = Map()
	for i = m to 1:
		for j = n to 1:
			if X[i] == Y[j]:
				dpTable[i, j] = dpTable[i + 1, j + 1] + 1
				lcsChoices[i, j] = [i + 1, j + 1]
			else:
				skipI = dpTable[i + 1, j]
				skipJ = dpTable[i, j + 1]
				if skipI > skipJ:
					dpTable[i, j] = skipI
					lcsChoices[i, j] = [i + 1, j]
				else:
					dpTable[i, j] = skipJ
					lcsChoices[i, j] = [i, j + 1]

	return dpTable[1, 1]

